.subtitle{text-align:center;color:#888;margin-bottom:30px;font-size:14px}
.steps{display:flex;justify-content:center;gap:10px;margin-bottom:30px;flex-wrap:wrap}
.step{padding:8px 16px;border-radius:20px;background:#1a1a2e;border:1px solid #333;font-size:13px;transition:all .3s}
.step.active{background:#00d4ff;color:#000;border-color:#00d4ff}
.step.done{background:#2a4a3a;border-color:#00ff88;color:#00ff88}
.card{background:rgba(26,26,46,.9);border-radius:12px;padding:25px;margin-bottom:20px;border:1px solid #333}
.card-title{color:#00d4ff;font-size:18px;margin-bottom:15px;border-bottom:1px solid #333;padding-bottom:10px}
.options-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px}
.option-btn{padding:15px;border-radius:8px;background:#252540;border:2px solid #333;cursor:pointer;transition:all .3s;text-align:center}
.option-btn:hover{border-color:#00d4ff;background:#2a2a4a}
.option-btn.selected{border-color:#00d4ff;background:rgba(0,212,255,.15)}
.option-btn.disabled{opacity:.4;cursor:not-allowed;pointer-events:none}
.option-btn .name{font-size:16px;font-weight:bold;margin-bottom:5px}
.option-btn .desc{font-size:11px;color:#888}
.option-btn .tag{font-size:10px;padding:2px 6px;border-radius:4px;margin-top:5px;display:inline-block}
.tag-legend{background:#ff6b00;color:#000}
.tag-special{background:#9b59b6;color:#fff}
.form-group{margin-bottom:15px}
.form-group label{display:block;margin-bottom:5px;color:#888;font-size:13px}
.form-group input,.form-group select{width:100%;padding:12px;border-radius:8px;border:1px solid #333;background:#252540;color:#e0e0e0;font-size:14px}
.form-group input:focus,.form-group select:focus{outline:none;border-color:#00d4ff}
.form-row{display:grid;grid-template-columns:1fr 1fr;gap:15px}
.preview{background:#1a1a2e;border-radius:8px;padding:20px;border:1px solid #00d4ff}
.preview-title{color:#00d4ff;font-size:14px;margin-bottom:15px}
.preview-item{display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid #333;font-size:13px}
.preview-item:last-child{border-bottom:none}
.preview-label{color:#888}
.preview-value{color:#00ff88}
.btn-group{display:flex;gap:10px;margin-top:20px}
.btn{padding:12px 30px;border-radius:8px;border:none;cursor:pointer;font-size:14px;transition:all .3s}
.btn-primary{background:#00d4ff;color:#000}
.btn-primary:hover{background:#00b8e0}
.btn-secondary{background:#333;color:#e0e0e0}
.btn-secondary:hover{background:#444}
.btn-create{background:linear-gradient(135deg,#00ff88,#00d4ff);color:#000;font-weight:bold;width:100%}
.step-panel{display:none}
.step-panel.active{display:block}
.warning{background:rgba(255,107,0,.2);border:1px solid #ff6b00;border-radius:8px;padding:10px;margin-top:10px;font-size:12px;color:#ff6b00}
.info{background:rgba(0,212,255,.1);border:1px solid #00d4ff;border-radius:8px;padding:10px;margin-top:10px;font-size:12px;color:#00d4ff}
</style>
</head>
<body>
<div class="container">
<h1>新渊暗都</h1>
<p class="subtitle">2026 · 多种族共存超级都市 · 霓虹与阴影交织</p>
<div class="steps">
<div class="step active" data-step="1">1.势力</div>
<div class="step" data-step="2">2.职业</div>
<div class="step" data-step="3">3.种族</div>
<div class="step" data-step="4">4.性别</div>
<div class="step" data-step="5">5.姓名/年龄</div>
<div class="step" data-step="6">6.确认创建</div>
</div>
<div class="step-panel active" id="step1">
<div class="card"><div class="card-title">选择你的势力</div><div class="options-grid" id="faction-options"></div><div class="info" id="faction-info" style="display:none"></div></div>
<div class="btn-group"><button class="btn btn-primary" onclick="nextStep(1)">下一步 →</button></div>
</div>
<div class="step-panel" id="step2">
<div class="card"><div class="card-title">选择你的职业</div><div class="options-grid" id="job-options"></div><div class="info" id="job-info" style="display:none"></div></div>
<div class="btn-group"><button class="btn btn-secondary" onclick="prevStep(2)">← 上一步</button><button class="btn btn-primary" onclick="nextStep(2)">下一步 →</button></div>
</div>
<div class="step-panel" id="step3">
<div class="card"><div class="card-title">选择你的种族</div><div class="options-grid" id="race-options"></div><div id="race-warning" class="warning" style="display:none"></div><div class="info" id="race-info" style="display:none"></div></div>
<div class="btn-group"><button class="btn btn-secondary" onclick="prevStep(3)">← 上一步</button><button class="btn btn-primary" onclick="nextStep(3)">下一步 →</button></div>
</div>
<div class="step-panel" id="step4">
<div class="card"><div class="card-title">选择你的性别</div><div class="options-grid" id="gender-options"></div><div id="gender-warning" class="warning" style="display:none"></div></div>
<div class="btn-group"><button class="btn btn-secondary" onclick="prevStep(4)">← 上一步</button><button class="btn btn-primary" onclick="nextStep(4)">下一步 →</button></div>
</div>
<div class="step-panel" id="step5">
<div class="card"><div class="card-title">填写你的基础信息</div><div class="form-row"><div class="form-group"><label>姓名</label><input type="text" id="char-name" placeholder="输入角色姓名" maxlength="20"></div><div class="form-group"><label>年龄 (16-300)</label><input type="number" id="char-age" min="16" max="300" value="25"></div></div></div>
<div class="btn-group"><button class="btn btn-secondary" onclick="prevStep(5)">← 上一步</button><button class="btn btn-primary" onclick="nextStep(5)">下一步 →</button></div>
</div>
<div class="step-panel" id="step6">
<div class="card"><div class="card-title">确认角色信息</div><div class="preview" id="char-preview"></div></div>
<div class="btn-group"><button class="btn btn-secondary" onclick="prevStep(6)">← 上一步</button><button class="btn btn-create" onclick="createCharacter()">确认创建角色</button></div>
</div>
</div>
<script>
var FACTIONS={'城防署':{desc:'官方治安，维护秩序',jobs:['外勤特工','灵能调查员'],location:'上城区·城防署总部·会议室',startingMoney:5000,weather:'晴朗',rumor:'下城区灵能波动异常'},'深渊议会':{desc:'绝对反派，追求神之容器',jobs:['暗影执行者','议会学者'],location:'深渊裂隙·深渊议会据点·议事厅',startingMoney:8000,weather:'极光',rumor:'议会调动暗影执行者'},'自由行者联盟':{desc:'零散佣兵',jobs:['赏金猎人','街区医生'],location:'中城区·自由行者酒吧·大厅',startingMoney:3000,weather:'阴天',rumor:'义体暴走者出没'},'暮光商会':{desc:'中立商人，情报交易',jobs:['情报掮客','器械师'],location:'上城区·暮光交易所·VIP厅',startingMoney:10000,weather:'多云',rumor:'沈星河调查旧案'}};
var RACES={'人类':{rarity:'普通',lockGender:null,blockFactions:[],desc:'适应性强，三路线皆可'},'精灵种':{rarity:'普通',lockGender:null,blockFactions:[],desc:'远古契约后裔，寿命300+'},'兽化种':{rarity:'普通',lockGender:null,blockFactions:[],desc:'兽灵血统，感官敏锐'},'血族种':{rarity:'特殊',lockGender:'女',blockFactions:['城防署'],desc:'初源之血，白日减半'},'半机械体':{rarity:'特殊',lockGender:null,blockFactions:['深渊议会'],desc:'先天义体化20%'},'天使种':{rarity:'传说',lockGender:'女',blockFactions:['深渊议会','暮光商会'],desc:'圣光审判庭遗民'},'恶魔种':{rarity:'传说',lockGender:'男',blockFactions:['城防署'],desc:'深渊叛逃者后裔'},'纯机械生命体':{rarity:'传说',lockGender:null,blockFactions:['深渊议会'],desc:'失落科技觉醒AI'}};
var JOBS={'外勤特工':{desc:'城防署前线作战',attributes:{灵能等级:10,义体化程度:10},outfit:{外套:'城防署制服外套',上衣:'制式衬衫',下装:'战术长裤',鞋子:'作战靴'},inventory:['城防署身份卡','通讯器','标准配枪'],task:'调查下城区灵能波动',objective:'查明波动源头'},'灵能调查员':{desc:'灵能事件专家',attributes:{灵能等级:20},outfit:{外套:'城防署制服外套',上衣:'制式衬衫',下装:'战术长裤',鞋子:'作战靴'},inventory:['城防署身份卡','通讯器','灵能探测仪'],task:'调查觉醒者失踪案',objective:'分析波动残留'},'暗影执行者':{desc:'议会精锐刺客',attributes:{灵能等级:30,义体化程度:20},erosion:15,outfit:{外套:'议会战术斗篷',上衣:'暗影作战服',下装:'战术长裤',鞋子:'静音作战靴'},inventory:['议会徽章','通讯器','深渊短刃'],task:'绑架光系觉醒者',objective:'带回议会'},'议会学者':{desc:'议会研究员',attributes:{灵能等级:20,基因强化等级:30},erosion:10,outfit:{外套:'学者长袍',上衣:'实验服',下装:'长裙',鞋子:'低跟皮鞋'},inventory:['议会学者徽章','便携实验箱'],task:'窃取基因稳定剂配方',objective:'获取配方'},'赏金猎人':{desc:'佣兵',attributes:{灵能等级:10,义体化程度:10},outfit:{外套:'皮质夹克',上衣:'汗衫',下装:'工装裤',鞋子:'军靴'},inventory:['联盟徽章','通讯器','改装手枪'],task:'猎杀义体暴走者',objective:'猎杀目标'},'街区医生':{desc:'医疗者',attributes:{基因强化等级:20,义体化程度:10},outfit:{外套:'白大褂',上衣:'手术服',下装:'工装裤',鞋子:'防滑鞋'},inventory:['联盟徽章','便携医疗箱'],task:'救治兽化种老大',objective:'义体排异手术'},'情报掮客':{desc:'情报交易者',attributes:{基因强化等级:10},outfit:{外套:'黑色风衣',上衣:'衬衫',下装:'西裤',鞋子:'皮鞋'},inventory:['商会徽章','加密通讯器'],task:'向沈星河转卖情报',objective:'伪装来源'},'器械师':{desc:'技术专家',attributes:{义体化程度:15},outfit:{外套:'工装外套',上衣:'工作服',下装:'多袋工装裤',鞋子:'防静电靴'},inventory:['商会徽章','便携工具箱'],task:'更换林夜机械臂核心',objective:'扫描左臂数据'}};
var selectedFaction=null,selectedJob=null,selectedRace=null,selectedGender=null;
function init(){renderFactionOptions()}
function renderFactionOptions(){var c=document.getElementById('faction-options');c.innerHTML='';Object.keys(FACTIONS).forEach(function(n){var b=document.createElement('div');b.className='option-btn';b.innerHTML='<div class="name">'+n+'</div><div class="desc">'+FACTIONS[n].desc+'</div>';b.onclick=function(){selectFaction(n,this)};c.appendChild(b)})}
function renderJobOptions(){var c=document.getElementById('job-options');c.innerHTML='';FACTIONS[selectedFaction].jobs.forEach(function(n){var b=document.createElement('div');b.className='option-btn';b.innerHTML='<div class="name">'+n+'</div><div class="desc">'+JOBS[n].desc+'</div>';b.onclick=function(){selectJob(n,this)};c.appendChild(b)})}
function renderRaceOptions(){var c=document.getElementById('race-options');c.innerHTML='';Object.keys(RACES).forEach(function(n){var r=RACES[n];var blocked=r.blockFactions.indexOf(selectedFaction)>=0;var b=document.createElement('div');b.className='option-btn'+(blocked?' disabled':'');var tag=r.rarity==='传说'?'<span class="tag tag-legend">传说</span>':r.rarity==='特殊'?'<span class="tag tag-special">特殊</span>':'';b.innerHTML='<div class="name">'+n+'</div><div class="desc">'+r.desc+'</div>'+tag;if(!blocked)b.onclick=function(){selectRace(n,this)};c.appendChild(b)})}
function renderGenderOptions(){var c=document.getElementById('gender-options');c.innerHTML='';var r=RACES[selectedRace];var locked=r.lockGender;['男','女'].forEach(function(g){var b=document.createElement('div');var isLocked=locked&&locked!==g;b.className='option-btn'+(isLocked?' disabled':'')+(selectedGender===g?' selected':'');b.innerHTML='<div class="name">'+g+'</div>';if(!isLocked){b.onclick=function(){selectGender(g,this)};if(locked===g){selectedGender=g;b.classList.add('selected')}}c.appendChild(b)});if(locked){document.getElementById('gender-warning').textContent=selectedRace+'锁定性别为'+locked;document.getElementById('gender-warning').style.display='block';selectedGender=locked}else{document.getElementById('gender-warning').style.display='none'}}
function renderPreview(){var n=document.getElementById('char-name').value||'待设定';var a=document.getElementById('char-age').value;var r=RACES[selectedRace];var maxAge=selectedRace==='精灵种'?300:100;var finalAge=Math.min(Math.max(parseInt(a)||25,16),maxAge);document.getElementById('char-age').value=finalAge;document.getElementById('char-preview').innerHTML='<div class="preview-title">角色预览</div><div class="preview-item"><span class="preview-label">姓名</span><span class="preview-value">'+n+'</span></div><div class="preview-item"><span class="preview-label">势力</span><span class="preview-value">'+selectedFaction+'</span></div><div class="preview-item"><span class="preview-label">职业</span><span class="preview-value">'+selectedJob+'</span></div><div class="preview-item"><span class="preview-label">种族</span><span class="preview-value">'+selectedRace+' ('+r.rarity+')</span></div><div class="preview-item"><span class="preview-label">性别</span><span class="preview-value">'+selectedGender+'</span></div><div class="preview-item"><span class="preview-label">年龄</span><span class="preview-value">'+finalAge+'岁</span></div><div class="preview-item"><span class="preview-label">种族特性</span><span class="preview-value" style="font-size:11px">'+r.desc+'</span></div>'}
function selectFaction(n,el){selectedFaction=n;document.querySelectorAll('#faction-options .option-btn').forEach(function(b){b.classList.remove('selected')});el.classList.add('selected');document.getElementById('faction-info').textContent=FACTIONS[n].desc;document.getElementById('faction-info').style.display='block'}
function selectJob(n,el){selectedJob=n;document.querySelectorAll('#job-options .option-btn').forEach(function(b){b.classList.remove('selected')});el.classList.add('selected');document.getElementById('job-info').textContent=JOBS[n].desc;document.getElementById('job-info').style.display='block'}
function selectRace(n,el){selectedRace=n;document.querySelectorAll('#race-options .option-btn').forEach(function(b){b.classList.remove('selected')});el.classList.add('selected');document.getElementById('race-info').textContent=RACES[n].desc;document.getElementById('race-info').style.display='block'}
function selectGender(g,el){selectedGender=g;document.querySelectorAll('#gender-options .option-btn').forEach(function(b){b.classList.remove('selected')});el.classList.add('selected')}
function nextStep(cur){if(cur===1&&!selectedFaction){alert('请选择一个势力');return}if(cur===2&&!selectedJob){alert('请选择一个职业');return}if(cur===3&&!selectedRace){alert('请选择一个种族');return}if(cur===4&&!selectedGender){alert('请选择性别');return}if(cur===5){var n=document.getElementById('char-name').value.trim();if(!n){alert('请输入角色姓名');return}}document.querySelector('.step[data-step="'+cur+'"]').classList.remove('active');document.querySelector('.step[data-step="'+cur+'"]').classList.add('done');document.querySelector('.step[data-step="'+(cur+1)+'"]').classList.add('active');document.getElementById('step'+cur).classList.remove('active');document.getElementById('step'+(cur+1)).classList.add('active');if(cur===1)renderJobOptions();if(cur===2)renderRaceOptions();if(cur===3)renderGenderOptions();if(cur===5)renderPreview()}
function prevStep(cur){document.querySelector('.step[data-step="'+cur+'"]').classList.remove('active');document.querySelector('.step[data-step="'+(cur-1)+'"]').classList.remove('done');document.querySelector('.step[data-step="'+(cur-1)+'"]').classList.add('active');document.getElementById('step'+cur).classList.remove('active');document.getElementById('step'+(cur-1)).classList.add('active')}
var adventureStarted=false;
function createCharacter(){
if(adventureStarted)return;
var n=document.getElementById('char-name').value.trim();
var a=parseInt(document.getElementById('char-age').value);
var f=FACTIONS[selectedFaction];var j=JOBS[selectedJob];var r=RACES[selectedRace];var g=selectedGender;if(r.lockGender)g=r.lockGender;var maxAge=selectedRace==='精灵种'?300:100;var age=Math.min(Math.max(a||25,16),maxAge);var outfit=Object.assign({内衣:'无',内裤:'普通内裤'},j.outfit||{});if(g==='女')outfit.内衣=outfit.内衣==='无'?'运动内衣':outfit.内衣;var attr=Object.assign({灵能等级:0,基因强化等级:0,义体化程度:0,特殊能力:'无'},j.attributes||{});if(selectedRace==='纯机械生命体'){attr.灵能等级=0;attr.基因强化等级=0;attr.义体化程度=100;attr.特殊能力='机械意识觉醒'}else if(selectedRace==='半机械体'){attr.义体化程度=Math.max(attr.义体化程度,20)}var status={HP:100,体力:100,精神力:100,侵蚀度:0};if(selectedRace==='纯机械生命体')status.精神力=0;if(j.erosion)status.侵蚀度=j.erosion;
var initvar={主角:{基础:{姓名:n,种族:selectedRace,年龄:age,职业:selectedJob,性别:g,势力:selectedFaction,金钱:f.startingMoney,外貌身材:'待生成'},属性:attr,状态:status,着装:outfit,背包:j.inventory||['身份卡','通讯器'],战斗定位:'中排输出',当前情绪:'平静'},世界:{当前时间:'6月29日·星期日 08:00:00',当前地点:f.location,经过天数:0,天气:f.weather,都市流言:f.rumor,城市活跃度:'正常'},任务:{当前任务:j.task||'无',任务目标:j.objective||'无',子任务:'无',已获取线索:'无',任务状态:j.task?'进行中':'无任务'},社交:{已遇NPC列表:[],当前交互NPC:'无',NPC关系:{}}};
adventureStarted=true;
var btn=document.querySelector('.btn-create');if(btn){btn.disabled=true;btn.textContent='✅ 已创建，请勿重复点击';btn.style.opacity='.6';btn.style.cursor='not-allowed'}
var narrative='角色创建完成。我叫'+n+'，'+selectedRace+'，'+selectedFaction+'的'+selectedJob+'。现在，故事开始了。请根据我的身份展开开场叙事，并为我的外貌身材生成一段描写。';
var patches=[];patches.push({op:'replace',path:'/主角/基础/姓名',value:n});patches.push({op:'replace',path:'/主角/基础/种族',value:selectedRace});patches.push({op:'replace',path:'/主角/基础/年龄',value:age});patches.push({op:'replace',path:'/主角/基础/职业',value:selectedJob});patches.push({op:'replace',path:'/主角/基础/性别',value:g});patches.push({op:'replace',path:'/主角/基础/势力',value:selectedFaction});patches.push({op:'replace',path:'/主角/基础/金钱',value:f.startingMoney});patches.push({op:'replace',path:'/主角/属性/灵能等级',value:attr.灵能等级});patches.push({op:'replace',path:'/主角/属性/基因强化等级',value:attr.基因强化等级});patches.push({op:'replace',path:'/主角/属性/义体化程度',value:attr.义体化程度});patches.push({op:'replace',path:'/主角/属性/特殊能力',value:attr.特殊能力});patches.push({op:'replace',path:'/主角/状态/侵蚀度',value:status.侵蚀度});patches.push({op:'replace',path:'/主角/状态/精神力',value:status.精神力});patches.push({op:'replace',path:'/主角/着装/外套',value:outfit.外套||'无'});patches.push({op:'replace',path:'/主角/着装/上衣',value:outfit.上衣||'无'});patches.push({op:'replace',path:'/主角/着装/下装',value:outfit.下装||'无'});patches.push({op:'replace',path:'/主角/着装/内衣',value:outfit.内衣||'无'});patches.push({op:'replace',path:'/主角/着装/内裤',value:outfit.内裤||'无'});patches.push({op:'replace',path:'/主角/着装/鞋子',value:outfit.鞋子||'无'});patches.push({op:'replace',path:'/主角/着装/饰品',value:outfit.饰品||'无'});patches.push({op:'replace',path:'/主角/背包',value:j.inventory||['身份卡','通讯器']});patches.push({op:'replace',path:'/世界/当前地点',value:f.location});patches.push({op:'replace',path:'/世界/天气',value:f.weather});patches.push({op:'replace',path:'/世界/都市流言',value:f.rumor});patches.push({op:'replace',path:'/任务/当前任务',value:j.task||'无'});patches.push({op:'replace',path:'/任务/任务目标',value:j.objective||'无'});patches.push({op:'replace',path:'/任务/任务状态',value:j.task?'进行中':'无任务'});
var ps=JSON.stringify(patches);
var uv='<Up'+'dateVariable>';var ue='</Up'+'dateVariable>';
var fp='/send '+narrative+'\n\n<span style="display:none;">\n'+uv+'\n<JSONPatch>\n'+ps+'\n</JSONPatch>\n'+ue+'\n</span>|/trigger';
